codeExamples.code:
-- Sample table: employees (id, name, department, salary, join_date)
-- 10 rows already inserted (see Explanation section)

-- All columns, all rows
SELECT * FROM employees;

-- Only specific columns
SELECT name, salary FROM employees;

commonMistakes.wrongCode:
-- Goal: IT or HR employees earning over 50000
SELECT name FROM employees
WHERE department = 'IT' OR department = 'HR' AND salary > 50000;

-- If some departments are NULL in a subquery:
SELECT name FROM employees
WHERE department NOT IN ('IT', 'HR', NULL);

commonMistakes.correctCode:
SELECT name FROM employees
WHERE department NOT IN ('IT', 'HR')
  AND department IS NOT NULL;

codingChallenges.solution:
SELECT name, salary, join_date
FROM employees
WHERE department = 'IT' AND salary > 70000;

SELECT name, salary AS pay
FROM employees
WHERE salary BETWEEN 55000 AND 85000;

SELECT *
FROM employees
WHERE NOT (department = 'HR' AND salary < 50000);

SELECT name, salary * 12 AS annual_pay
FROM employees
WHERE salary * 12 > 800000;

SELECT *
FROM employees
WHERE name IN ('Aarav Sharma', 'Ananya Singh', 'Diya Nair');
